var removeDuplicatesTool = defineTool({
  name: "remove_duplicates",
  description: "Optimized duplicate deletion pattern. Scans all collections and removes duplicates in batches of 50 to minimize round-trips. Supports dry run to report counts without deleting.",
  inputSchema: exports_external.object({
    dryRun: exports_external.boolean().optional().default(true).describe("If true, only reports the number of duplicates found without deleting them."),
    skipCache: exports_external.boolean().optional().describe("Force a fresh fetch from the API, bypassing the local cache")
  }),
  handler: async (args, { raindropService, reportProgress }) => {
    const progress = typeof reportProgress === "function" ? reportProgress : () => {};
    progress({ progress: 0, total: 100 });
    const globalDuplicates = await raindropService.getBookmarks({
      duplicates: true,
      perPage: 1
    }, args.skipCache);
    const totalEstimated = globalDuplicates.count;
    if (totalEstimated === 0) {
      return {
        content: [textContent("No duplicates found in the entire library.")]
      };
    }
    const collections = await raindropService.getCollections(args.skipCache);
    const collectionDuplicatesMap = new Map;
    let totalFound = 0;
    const allCollectionIds = [
      0,
      ...collections.map((c) => c._id).filter((id) => id !== undefined)
    ];
    for (let i = 0;i < allCollectionIds.length; i++) {
      const colId = allCollectionIds[i];
      if (colId === undefined)
        continue;
      progress({
        progress: 10 + i / allCollectionIds.length * 40,
        total: 100
      });
      const colDuplicates = await raindropService.getBookmarks({
        collection: colId,
        duplicates: true,
        perPage: 50
      }, args.skipCache);
      if (colDuplicates.count > 0) {
        let allIds = colDuplicates.items.map((item) => item._id).filter((id) => id !== undefined);
        if (colDuplicates.count > 50) {
          const totalPages = Math.ceil(colDuplicates.count / 50);
          for (let p = 1;p < totalPages; p++) {
            const nextBatch = await raindropService.getBookmarks({
              collection: colId,
              duplicates: true,
              perPage: 50,
              page: p
            }, args.skipCache);
            allIds = allIds.concat(nextBatch.items.map((item) => item._id).filter((id) => id !== undefined));
          }
        }
        collectionDuplicatesMap.set(colId, allIds);
        totalFound += allIds.length;
      }
    }
    if (totalFound === 0) {
      return {
        content: [
          textContent(`Global search estimated ${totalEstimated} duplicates, but per-collection scan found none. This may be due to cross-collection duplicates which cannot be safely bulk-deleted.`)
        ]
      };
    }
    if (args.dryRun) {
      let report = `Dry Run: Found ${totalFound} duplicates across ${collectionDuplicatesMap.size} collections.
`;
      collectionDuplicatesMap.forEach((ids, colId) => {
        const colName = colId === 0 ? "Unsorted" : collections.find((c) => c._id === colId)?.title || `ID: ${colId}`;
        report += `- ${colName}: ${ids.length} duplicates
`;
      });
      report += `
To delete these items, call this tool again with 'dryRun: false'.`;
      return { content: [textContent(report)] };
    }
    let totalDeleted = 0;
    const errors3 = [];
    const collectionEntries = Array.from(collectionDuplicatesMap.entries());
    for (let i = 0;i < collectionEntries.length; i++) {
      const entry = collectionEntries[i];
      if (!entry)
        continue;
      const [colId, ids] = entry;
      progress({
        progress: 50 + i / collectionEntries.length * 50,
        total: 100
      });
      for (let j = 0;j < ids.length; j += 50) {
        const batch = ids.slice(j, j + 50);
        try {
          const success2 = await raindropService.batchDeleteBookmarksInCollection(colId, batch);
          if (success2) {
            totalDeleted += batch.length;
          } else {
            errors3.push({
              collectionId: colId,
              ids: batch,
              message: "API returned failure"
            });
            return {
              content: [
                textContent(`Fail Fast: Stopped after error in collection ${colId}. Total deleted so far: ${totalDeleted}.
Errors: ${JSON.stringify(errors3)}`)
              ]
            };
          }
        } catch (error48) {
          errors3.push({
            collectionId: colId,
            ids: batch,
            message: error48.message
          });
          return {
            content: [
              textContent(`Fail Fast: Stopped after exception in collection ${colId}: ${error48.message}. Total deleted so far: ${totalDeleted}.
Errors: ${JSON.stringify(errors3)}`)
            ]
          };
        }
      }
    }
    return {
      content: [
        textContent(`Successfully deleted ${totalDeleted} duplicates across ${collectionDuplicatesMap.size} collections.`)
      ]
    };
  }
});
var cleanupTools = [
  libraryAuditTool,
  emptyTrashTool,
  cleanupCollectionsTool,
  removeDuplicatesTool
];

