var getCollectionTreeTool = defineTool({
  name: "get_collection_tree",
  description: "Returns a hierarchical view of all collections with full breadcrumb paths.",
  inputSchema: exports_external.object({
    skipCache: exports_external.boolean().optional().describe("Force a fresh fetch from the API, bypassing the local cache")
  }),
  handler: async (args, { raindropService }) => {
    const tree = await raindropService.getCollectionTree(args.skipCache);
    const formatNode = (node, indent = 0) => {
      let result = "  ".repeat(indent) + `- ${node.title} (ID: ${node._id}, Path: ${node.path}, Items: ${node.count || 0})
`;
      if (node.children && node.children.length > 0) {
        node.children.forEach((child) => {
          result += formatNode(child, indent + 1);
        });
      }
      return result;
    };
    let resultText = `Collection Hierarchy:
`;
    tree.forEach((node) => {
      resultText += formatNode(node);
    });
    return {
      content: [textContent(resultText)]
    };
  }
});
