var DiagnosticsInputSchema = exports_external.object({
  includeEnvironment: exports_external.boolean().optional().describe("Include environment info")
});
var DiagnosticsOutputSchema2 = exports_external.object({
  content: exports_external.array(exports_external.object({
    type: exports_external.literal("resource"),
    resource: exports_external.object({
      uri: exports_external.string(),
      mimeType: exports_external.string().optional(),
      text: exports_external.string()
    })
  }))
});
var createDiagnosticsTool = (serverVersion, getEnabledToolNames) => defineTool({
  name: "diagnostics",
  description: "Diagnostics resource and runtime metadata.",
  inputSchema: DiagnosticsInputSchema,
  outputSchema: DiagnosticsOutputSchema2,
  handler: async (args, context) => {
    const stats = context?.raindropService ? await context.raindropService.getUserStats() : null;
    let healthDetails = {};
    if (context?.raindropService) {
      const [broken, duplicates, untagged] = await Promise.all([
        context.raindropService.getBookmarks({ broken: true, perPage: 1 }),
        context.raindropService.getBookmarks({
          duplicates: true,
          perPage: 1
        }),
        context.raindropService.getBookmarks({ notag: true, perPage: 1 })
      ]);
      healthDetails = {
        brokenCount: broken.count,
        duplicateCount: duplicates.count,
        untaggedCount: untagged.count
      };
    }
    const diagnosticsData = {
      version: serverVersion,
      mcpProtocolVersion: "2025-11-25",
      sdkVersion: "1.25.3",
      nodeVersion: process.version,
      bunVersion: typeof Bun !== "undefined" ? Bun.version : undefined,
      os: process.platform,
      uptime: process.uptime(),
      startTime: new Date(Date.now() - process.uptime() * 1000).toISOString(),
      libraryHealth: stats ? {
        totalBookmarks: stats.bookmarks,
        totalCollections: stats.collections,
        totalHighlights: stats.highlights,
        totalTags: stats.tags,
        ...healthDetails
      } : undefined,
      env: {
        NODE_ENV: "development",
        MCP_DEBUG: process.env.MCP_DEBUG,
        MCP_TRANSPORT: process.env.MCP_TRANSPORT,
        RAINDROP_ACCESS_TOKEN: process.env.RAINDROP_ACCESS_TOKEN ? "set" : "unset"
      },
      enabledTools: getEnabledToolNames(),
      memory: process.memoryUsage()
    };
    return {
      content: [
        {
          type: "resource",
          resource: {
            uri: "diagnostics://server",
            mimeType: "application/json",
            text: JSON.stringify(diagnosticsData, null, 2)
          }
        }
      ]
    };
  }
});

