// src/tools/tags.ts
var tagManageTool = defineTool({
  name: "tag_manage",
  description: "Renames, merges, or deletes tags. Use the operation parameter to specify the action.",
  inputSchema: TagInputSchema,
  outputSchema: TagOutputSchema,
  handler: async (args, { raindropService }) => {
    switch (args.operation) {
      case "rename": {
        if (!args.tagNames || !args.newName)
          throw new ValidationError("tagNames and newName required for rename");
        const [primaryTag] = args.tagNames;
        if (!primaryTag)
          throw new ValidationError("tagNames must include at least one value");
        return raindropService.renameTag(args.collectionId, primaryTag, args.newName);
      }
      case "merge": {
        if (!args.tagNames || !args.newName)
          throw new ValidationError("tagNames and newName required for merge");
        return raindropService.mergeTags(args.collectionId, args.tagNames, args.newName);
      }
      case "delete": {
        if (!args.tagNames)
          throw new ValidationError("tagNames required for delete");
        return raindropService.deleteTags(args.collectionId, args.tagNames);
      }
      default:
        throw new ValidationError(`Unsupported operation: ${String(args.operation)}`);
    }
  }
});
var tagTools = [tagManageTool];

